"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[2323],{7534(e,o,t){t.r(o),t.d(o,{assets:()=>h,contentTitle:()=>r,default:()=>l,frontMatter:()=>n,metadata:()=>s,toc:()=>d});const s=JSON.parse('{"id":"stoicism/epictetus/discourses/book-3/discourses-book-3-chapter-21","title":"Discourses \u2014 Book 3, Chapter 21","description":"Book 3 \u2014 Chapter 21","source":"@site/docs/stoicism/epictetus/discourses/book-3/discourses-book-3-chapter-21.md","sourceDirName":"stoicism/epictetus/discourses/book-3","slug":"/stoicism/epictetus/discourses/book-3/discourses-book-3-chapter-21","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-3/discourses-book-3-chapter-21","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":21,"frontMatter":{"sidebar_position":21,"title":"Discourses \u2014 Book 3, Chapter 21","sidebar_label":"Book 3, Ch. 21"},"sidebar":"philosophersSidebar","previous":{"title":"Book 3, Ch. 20","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-3/discourses-book-3-chapter-20"},"next":{"title":"Book 3, Ch. 22","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-3/discourses-book-3-chapter-22"}}');var a=t(4848),i=t(8453);const n={sidebar_position:21,title:"Discourses \u2014 Book 3, Chapter 21",sidebar_label:"Book 3, Ch. 21"},r="Discourses",h={},d=[{value:"Book 3 \u2014 Chapter 21",id:"book-3--chapter-21",level:2},{value:"To Those Who Undertake The Profession Of Teacher With A Light Heart",id:"to-those-who-undertake-the-profession-of-teacher-with-a-light-heart",level:3},{value:"Text",id:"text",level:2}];function u(e){const o={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,i.R)(),...e.components},{Details:t}=o;return t||function(e,o){throw new Error("Expected "+(o?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,a.jsxs)(a.Fragment,{children:[(0,a.jsxs)("div",{style:{textAlign:"center"},children:[(0,a.jsx)(o.header,{children:(0,a.jsx)(o.h1,{id:"discourses",children:"Discourses"})}),(0,a.jsx)(o.h2,{id:"book-3--chapter-21",children:"Book 3 \u2014 Chapter 21"}),(0,a.jsx)(o.h3,{id:"to-those-who-undertake-the-profession-of-teacher-with-a-light-heart",children:"To Those Who Undertake The Profession Of Teacher With A Light Heart"})]}),"\n",(0,a.jsx)(o.p,{children:(0,a.jsx)(o.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,a.jsxs)(t,{open:!0,children:[(0,a.jsx)("summary",{children:"Text"}),(0,a.jsx)(o.h2,{id:"text",children:"Text"}),(0,a.jsx)(o.p,{children:"THOSE who have learnt precepts and nothing more are anxious to give them out at once, just as men with weak stomachs vomit food. First digest your precepts, and then you will not vomit them; undigested, they become vomit indeed, impure and uneatable. Show us that you have digested them to some purpose, and that your Governing Principle is changed, as athletes can show their shoulders, as a result of their training and eating, and as those who have acquired the arts can show"}),(0,a.jsx)(o.p,{children:"the result of their learning. The carpenter does not come and say, 'Hear me discourse on carpentry', but he undertakes a contract and builds a house and so shows that he has acquired the art. Do you likewise: eat as a man, drink as a man, adorn yourself, marry, get children, live a citizen's life; endure revilings, bear with an inconsiderate brother, bear with a father, a son, a travelling companion. Show us that you can do this, and then we shall see that you have in truth learnt something from the philosophers. Not you: you say, 'Come and hear me reading out comments!' Away with you, look for some one to disgorge your vomit on."}),(0,a.jsx)(o.p,{children:"'I assure you I will expound Chrysippus' doctrines to you as no one else can. I will break up his language and make it quite clear. I will add, it may be, a touch of Antipater's or Archedemus' verve.'"}),(0,a.jsx)(o.p,{children:"What! is it for this that young men are to leave their countries and their parents, that they may come and hear you expounding petty points of language? Ought they not to return ready to bear with others and work with them, tranquil and free from tumult, furnished with a provision for life's journey, which will enable them to bear what befalls them well and to adorn themselves thereby? And how are you to impart to them what you do not possess yourself? For your sole occupation from the first has been this--how you are to resolve syllogisms and variable arguments, and arguments concluding with a question."}),(0,a.jsx)(o.p,{children:"'But So-and-so gives lectures, why should not I?'"}),(0,a.jsx)(o.p,{children:"Slave, you cannot do this off-hand, and in a random fashion. It demands mature years, and a certain way of life, and the guidance of God."}),(0,a.jsx)(o.p,{children:"You say no: but no one sails from harbour without sacrificing to the gods and invoking their help, and men do not sow at random, but only when they have invoked Demeter; and when a man has laid his hand to a task so momentous as this without the gods' help, will he be secure and will those who come to him be fortunate in their coming? Man, what are you doing but making the Mysteries common? You say, 'There is a shrine at Eleusis, lo, here is one also: there is a hierophant there: I too will make a hierophant: there is a herald there, I too will appoint a herald: there is a torch-bearer there, I too will have a torch-bearer: there are torches there, so there are here: the cries are the same. What difference is there between our doings and the Mysteries?'"}),(0,a.jsx)(o.p,{children:"Most impious of men, is there no difference? The benefit of the Mysteries depends on proper place and time: one must approach with sacrifice and prayer, with body purified and mind ready and disposed to approach holy rites and ancient sanctities. Only so do the Mysteries bring benefit, only so do we arrive at the belief that all these things were established by those of old for our education and the amendment of our life. But you publish and divulge them out of place and out of"}),(0,a.jsx)(o.p,{children:"season, without sacrifices or purifying: you have not the dress which the hierophant should have, nor the proper hair, nor the fillet: you have not the right voice nor age, you have not lived pure as he has, but you have merely learnt off the words and say, 'The words have a holy power in themselves.'"}),(0,a.jsx)(o.p,{children:"You must approach the task in another fashion: it is momentous and full of mystery, not a chance gift which any one can command. The care of the young demands, it may be, more than wisdom: yes, by Zeus, one must have a certain readiness and special fitness, and a certain habit of body, and above all the counsel of God advising one to discharge this duty, as He counselled Socrates to examine men, and Diogenes to rebuke men in royal fashion, and Zeno to instruct and lay down precepts. You open a doctor's consulting-room with nothing but some drugs, without ever taking the trouble to acquire a knowledge of when or how they are applied. 'See, that's his remedy, eye-salve' (you say): 'I have that too.' Have you also the faculty of using it? Do you know when and how and to whom it will do good? Why then do you play at hazard with matters of highest moment, why are you reckless, why do you take in hand a task unsuited to your powers? Leave it to those who can do it and do it with distinction."}),(0,a.jsx)(o.p,{children:"Do not bring disgrace upon philosophy by your personal act, nor join those who disparage the profession; but if the study of precepts really attracts you, sit quietly and turn them over in your mind, but never call yourself a philosopher nor allow any one else to do so, but say: 'He is in error: I am unchanged; my will, my impulses, my assent, are what they were, and, in a word, I have not advanced from my position, but deal with impressions as before.' So think, so speak about yourself, if you would think aright. But if this is beyond you, then play at hazard and do as you are doing, for you will be acting in character."})]})]})}function l(e={}){const{wrapper:o}={...(0,i.R)(),...e.components};return o?(0,a.jsx)(o,{...e,children:(0,a.jsx)(u,{...e})}):u(e)}},8453(e,o,t){t.d(o,{R:()=>n,x:()=>r});var s=t(6540);const a={},i=s.createContext(a);function n(e){const o=s.useContext(i);return s.useMemo(function(){return"function"==typeof e?e(o):{...o,...e}},[o,e])}function r(e){let o;return o=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:n(e.components),s.createElement(i.Provider,{value:o},e.children)}}}]);